protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>().ToContainer("Products");

    // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
    // Preserve "Discriminator" so existing 500K documents remain queryable and
    // direct SQL queries referencing c.Discriminator continue to work.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // EF Core 9: id values no longer include the discriminator prefix.
    // Preserve the old "Product|123" format so FindAsync/point-reads hit
    // existing documents written by EF Core 8.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

    // EF Core 9: HasIndex now throws for Cosmos entities (was silently ignored).
    // Removed — manage indexing via the Cosmos container's indexing policy instead.
    // (was: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);)
}

